def is_implicit_concatenation(node):
    # Check for implicit concatenation of bytes and strings
    for child in node.children:
        if isinstance(child, ast.Num)
            return child.n in node.parent.body and isinstance(node.parent, ast.BinOp) and (isinstance(node.parent.left, ast.Str)
                or isinstance(node.parent.left, ast.Bytes)
                or isinstance(node.parent.right, ast.Str)
                or isinstance(node.parent.right, ast.Bytes))
    return False
